/**
 * Resets the input values to an empty array.
 */
reset() {
  this.inputValues = [];
  for (let index = 0; index < this.length(); index++) {
    this.inputValues.push(' ');
  }
}

/**
 * Converts the value string to input values and updates the inputValues array.
 */
mapValueToInputs() {
  this._emitOnComplete();
  if (!this.value) {
    return;
  }
  this.value.split('').map((v, i) => {
    this.inputValues[i] = v;
  });
}

/**
 * Removes focus from the component.
 */
blur(): void {
  AXHtmlUtil.blurElement(this.getHostElement());
}

/**
 * Checks if the component is focused or has any focused element.
 *
 * @returns boolean - True if the component has focus.
 */
hasFocus(): boolean {
  return AXHtmlUtil.hasFocus(this.getHostElement());
}

/**
 * Validates the component.
 *
 * @returns Promise<AXValidationSummary> - Validation result.
 */
async validate(): Promise<AXValidationSummary> {
  const container_classes = ['ax-editor-container', 'ax-checkbox', 'ax-radio'];
  const container = container_classes.some((c) => this.getHostElement().classList.contains(c))
    ? this.getHostElement()
    : this.getHostElement().querySelector('.ax-editor-container');
  const formField = container?.closest('ax-form-field') || container?.closest('ax-checkbox');
  const label = formField?.querySelector('ax-label') || formField?.querySelector('label');
  //
  const rules = this.validationService.ruleFor(this.value);
  this.validationRules.forEach((r) => {
    r.options['title'] = (label?.firstChild?.textContent ?? this.name)?.replace('*', '').trim();
    rules.addRule(r.rule as any, r.options);
  });
  const result = await rules.validate();
  if (result.result) {
    this.setState('clear');
  } else {
    const message = result.rules.find((c) => !c.result).message;
    this.setState('error', message);
  }
  return result;
}

/**
 * Resets validation errors.
 */
resetErrors(): void {
  this.setState('clear');
}

/**
 * Commits a value with optional user interaction flag.
 *
 * @param value - The value to commit.
 * @param u - Optional flag indicating if this is a user interaction.
 */
commitValue(value: T, u = false): void {
  if (u) {
    this.markAsTouched();
    this.markAsDirty();
    this._isUserInteraction = true;
  }
  this.writeValue(value);
}

/**
 * Writes a value to the component (ControlValueAccessor method).
 *
 * @param value - The value to write.
 */
writeValue(value: T): void {
  this.value = value;
}

/**
 * Registers a change callback function (ControlValueAccessor method).
 *
 * @param fn - The callback function to register.
 */
registerOnChange(fn: (value: T) => void): void {
  this.onChangeCallback = fn;
}

/**
 * Registers a touched callback function (ControlValueAccessor method).
 *
 * @param fn - The callback function to register.
 */
registerOnTouched(fn: () => void): void {
  this.onTouchedCallback = fn;
}

/**
 * Sets the disabled state of the component (ControlValueAccessor method).
 *
 * @param isDisabled - Whether the component should be disabled.
 */
setDisabledState(isDisabled: boolean): void {
  this.disabled = isDisabled;
}

/**
 * Adds a validation rule.
 *
 * @param rule - The validation rule to add.
 */
addValidationRule(rule: AXFormValidationRule): void {
  this.validationRules.push(rule);
  this.validationRulesChange.emit(this.validationRules);
}

/**
 * Removes a validation rule.
 *
 * @param ruleToRemove - The validation rule to remove.
 */
removeValidationRule(ruleToRemove: AXFormValidationRule): void {
  this.validationRules = this.validationRules.filter((r) => {
    if (r.rule !== ruleToRemove.rule) {
      return true;
    }
    // Create copies of options without the 'title' property
    const rOptionsSanitized = omit(r.options, ['title']);
    const ruleToRemoveOptionsSanitized = omit(ruleToRemove.options, ['title']);

    return !isEqual(rOptionsSanitized, ruleToRemoveOptionsSanitized);
  });
  this.validationRulesChange.emit(this.validationRules);
  this.setState('clear');
}

/**
 * Gets the host HTML element of the component.
 *
 * @returns T - The native DOM element associated with this component.
 */
getHostElement<T = HTMLElement>(): T {
  return this._elementRef?.nativeElement as T;
}

/**
 * Sets a component option with optional lifecycle callbacks.
 *
 * @param option - The option configuration containing the name, value and optional before/after callbacks.
 */
setOption<T = any>(option: MXComponentSetOption<T>) {
  const oldValue = this[option.name];
  let newValue = this.internalOptionChanging({
    name: option.name,
    value: option.value,
  });
  if (option.beforeCallback) {
    newValue = option.beforeCallback(oldValue, newValue);
  }
  if (oldValue != newValue) {
    this[`_${option.name}`] = option.value;
    this.onOptionChanged.emit({
      component: this,
      name: option.name,
      newValue,
      oldValue,
    });
    const emitter = this[`${option.name}Change`] as EventEmitter<any>;
    emitter?.emit(newValue);
    this.internalOptionChanged({ name: option.name, value: newValue });
  }
  if (option.afterCallback) option.afterCallback(oldValue, newValue);
}
